// Local and Remote Authentication Management
package radiusmanager

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40000/idl"
	"github.com/arminguenther/xeruspower-go/v40000/radius/radiusserversettings"
)

const (
	ERR_INVALID_CFG           int32 = 1 // The server configuration is invalid
	ERR_SERVER_UNSPECIFIED    int32 = 2 // Unspecified error
	ERR_INVALID_SHARED_SECRET int32 = 3 // The shared secret is invalid
	ERR_SERVER_UNREACHABLE    int32 = 4 // RADIUS server could not be contacted
	ERR_AUTHENTICATION_FAILED int32 = 5 // User could not be authenticated
	ERR_NO_ROLES              int32 = 6 // No roles are defined for the user
	ERR_NO_KNOWN_ROLES        int32 = 7 // No known rules are defined for the user
)

// RADIUS server configuration interface
type RadiusManager interface {
	idl.Object

	// Get a list of RADIUS server settings
	//
	//	@return list of radius.ServerSettings
	GetRadiusServers(ctx context.Context) ([]radiusserversettings.ServerSettings, error)

	// Sets a list of RADIUS servers.
	// Any existing RADIUS Server configuration will be cleared / overwritten.
	//
	//	@return 0                            on success
	//	@return ERR_INVALID_CFG           in case of invalid configuration
	SetRadiusServers(ctx context.Context, serverList []radiusserversettings.ServerSettings) (int32, error)

	// Tests an RADIUS server configuration.
	//
	//	@return 0                                    on success
	//	@return ERR_SERVER_UNSPECIFIED            an unspecified error occurred
	//	@return ERR_INVALID_CFG                   RADIUS server configuration is invalid (reused from setRadiusServers)
	//	@return ERR_INVALID_SHARED_SECRET         the shared secret is invalid
	//	@return ERR_SERVER_UNREACHABLE            RADIUS server could not be contacted
	//	@return ERR_AUTHENTICATION_FAILED         user could not be authenticated
	//	@return ERR_NO_ROLES                      no roles are defined for the user
	//	@return ERR_NO_KNOWN_ROLES                no known roles are defined for the user
	TestRadiusServer(ctx context.Context, username string, password string, settings radiusserversettings.ServerSettings) (int32, error)
}
